MOD = 10**9 + 7

def mod_add(a, b):
    return (a % MOD + b % MOD) % MOD

def mod_sub(a, b):
    return (a % MOD - b % MOD + MOD) % MOD

def mod_mul(a, b):
    return (a % MOD * b % MOD) % MOD

# Example: Calculate (123456789 * 987654321) % MOD
result = mod_mul(123456789, 987654321)
print(f"Result: {result}")  # Safe from overflow

def prime_factorization(n):
    factors = {}
    d = 2
    while d * d <= n:
        while n % d == 0:
            factors[d] = factors.get(d, 0) + 1
            n //= d
        d += 1
    if n > 1:
        factors[n] = 1
    return factors

def count_divisors(n):
    factors = prime_factorization(n)
    count = 1
    for exp in factors.values():
        count *= (exp + 1)
    return count

# Example
n = 360  # 2^3 × 3^2 × 5^1
print(f"Prime factors of {n}: {prime_factorization(n)}")
print(f"Number of divisors: {count_divisors(n)}")  # (3+1)(2+1)(1+1) = 24

def sieve_of_eratosthenes(n):
    """Return list of all primes <= n"""
    if n < 2:
        return []
    is_prime = [True] * (n + 1)
    is_prime[0] = is_prime[1] = False

    for i in range(2, int(n**0.5) + 1):
        if is_prime[i]:
            # Mark multiples starting from i²
            for j in range(i*i, n + 1, i):
                is_prime[j] = False

    return [i for i in range(n + 1) if is_prime[i]]

def linear_sieve(n):
    """Return primes and smallest prime factor (SPF) for each number"""
    spf = list(range(n + 1))  # spf[i] = i initially
    primes = []
    for i in range(2, n + 1):
        if spf[i] == i:  # i is prime
            primes.append(i)
        for p in primes:
            if p > spf[i] or i * p > n:
                break
            spf[i * p] = p
    return primes, spf

primes = sieve_of_eratosthenes(100)
print(f"Primes up to 100: {primes}")

MOD = 10**9 + 7

def mod_inverse_fermat(a, m=MOD):
    """Using Fermat's theorem (m must be prime)"""
    return pow(a, m - 2, m)

def mod_inverse_extended_gcd(a, m):
    """Using Extended Euclidean Algorithm"""
    def extended_gcd(a, b):
        if b == 0:
            return a, 1, 0
        g, x1, y1 = extended_gcd(b, a % b)
        return g, y1, x1 - (a // b) * y1

    g, x, _ = extended_gcd(a % m, m)
    if g != 1:
        return None  # Inverse doesn't exist
    return (x % m + m) % m

def precompute_inverses(n, m=MOD):
    """Precompute inverses for 1 to n"""
    inv = [0, 1] + [0] * (n - 1)
    for i in range(2, n + 1):
        inv[i] = (m - (m // i) * inv[m % i] % m) % m
    return inv

# Example: Division in modular arithmetic
a, b = 100, 7
result = (a * mod_inverse_fermat(b)) % MOD
print(f"100 / 7 mod MOD = {result}")

def count_coprime(n, primes):
    """Count integers in [1,n] coprime to all given primes"""
    m = len(primes)
    total = 0

    # Iterate all non-empty subsets using bitmask
    for mask in range(1, 1 << m):
        product = 1
        bits = 0
        for i in range(m):
            if mask & (1 << i):
                product *= primes[i]
                bits += 1
        # Add or subtract based on parity
        if bits & 1:
            total += n // product
        else:
            total -= n // product

    return n - total  # Numbers NOT divisible by any prime

def euler_totient(n):
    """Count integers in [1,n] coprime to n"""
    result = n
    p = 2
    temp = n
    while p * p <= temp:
        if temp % p == 0:
            while temp % p == 0:
                temp //= p
            result -= result // p
        p += 1
    if temp > 1:
        result -= result // temp
    return result

print(f"Coprimes to [2,3,5] in [1,30]: {count_coprime(30, [2,3,5])}")
print(f"φ(12) = {euler_totient(12)}")  # 4: {1,5,7,11}

def extended_gcd(a, b):
    if b == 0:
        return a, 1, 0
    g, x, y = extended_gcd(b, a % b)
    return g, y, x - (a // b) * y

def crt(remainders, moduli):
    if len(remainders) != len(moduli):
        return None
    M = 1
    for m in moduli:
        M *= m
    x = 0
    for r, m in zip(remainders, moduli):
        Mi = M // m
        _, yi, _ = extended_gcd(Mi, m)
        x += r * Mi * yi
    return x % M, M

solution, mod = crt([2, 3, 2], [3, 5, 7])
print(f"x = {solution} (mod {mod})")  # x = 23 (mod 105)

MOD = 10**9 + 7

def mat_mult(A, B):
    """Multiply two square matrices mod MOD"""
    n = len(A)
    C = [[0]*n for _ in range(n)]
    for i in range(n):
        for j in range(n):
            for k in range(n):
                C[i][j] = (C[i][j] + A[i][k] * B[k][j]) % MOD
    return C

def mat_pow(M, exp):
    """Compute M^exp mod MOD using binary exponentiation"""
    n = len(M)
    result = [[1 if i==j else 0 for j in range(n)] for i in range(n)]  # Identity

    while exp > 0:
        if exp & 1:
            result = mat_mult(result, M)
        M = mat_mult(M, M)
        exp >>= 1
    return result

def fibonacci(n):
    """Compute n-th Fibonacci number in O(log n)"""
    if n <= 1:
        return n
    M = [[1, 1], [1, 0]]
    result = mat_pow(M, n - 1)
    return result[0][0]

print(f"F(10) = {fibonacci(10)}")  # 55
print(f"F(50) = {fibonacci(50)}")
print(f"F(10^9) mod MOD = {fibonacci(10**9)}")

def build_2d_prefix(matrix):
    rows, cols = len(matrix), len(matrix[0])
    P = [[0]*(cols+1) for _ in range(rows+1)]
    for i in range(1, rows+1):
        for j in range(1, cols+1):
            P[i][j] = matrix[i-1][j-1] + P[i-1][j] + P[i][j-1] - P[i-1][j-1]
    return P

def query_2d(P, r1, c1, r2, c2):
    return P[r2+1][c2+1] - P[r1][c2+1] - P[r2+1][c1] + P[r1][c1]

matrix = [[1,2,3],[4,5,6],[7,8,9]]
P = build_2d_prefix(matrix)
print(f"Sum (1,1)→(2,2) = {query_2d(P, 1, 1, 2, 2)}")  # 5+6+8+9 = 28

def iterate_submasks(mask):
    """Yield all submasks of mask (including mask itself, excluding 0)"""
    s = mask
    while s > 0:
        yield s
        s = (s - 1) & mask

# Example: submasks of 0b1101 (13)
mask = 0b1101  # {0, 2, 3}
print(f"Submasks of {bin(mask)}:")
for s in iterate_submasks(mask):
    print(f"  {bin(s)} = {s}")
# 1101, 1100, 1001, 1000, 0101, 0100, 0001

# Total submasks = 2^(popcount(mask)) = 2^3 = 8 (including 0)
